// src/components/CouponForm/index.jsx

import React from 'react';
import { useForm } from 'react-hook-form';
import { BASE_URL } from '../../utils/api';

// Компонент теперь принимает className для стилизации из MainPage.module.css
const CouponForm = ({ className }) => { 
  const { 
    register, 
    handleSubmit, 
    // Нам все еще нужен errors для работы useForm, 
    // но мы не будем его использовать для рендеринга.
    formState: { errors },
    reset 
  } = useForm();

  const onSubmit = async (data) => {
    // Внимание: handleSubmit блокирует вызов onSubmit, если есть ошибки.
    // Если вы не видите alert 'Ошибка при отправке заявки', 
    // это значит, что валидация useForm не пройдена.
    try {
      const response = await fetch(`${BASE_URL}/sale/send`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ 
            name: data.name, 
            phone: data.phone,
            email: data.email 
        }),
      });

      if (response.ok) {
        alert('Спасибо! Ваш купон на скидку отправлен.');
        reset(); 
      } else {
        alert('Ошибка при отправке заявки.');
      }
    } catch (error) {
      console.error('Ошибка сети:', error);
      alert('Ошибка соединения с сервером.');
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className={className}>

        {/* 1. NAME FIELD */}
        <input
            type="text"
            placeholder="Name"
            {...register('name', { 
                required: 'Введите имя',
            })}
        />
        {/* ❌ УДАЛЕНО: {errors.name && <p className="error">{errors.name.message}</p>} */}

        {/* 2. PHONE NUMBER FIELD */}
        <input
            type="tel"
            placeholder="Phone number"
            {...register('phone', { 
                required: 'Введите номер телефона',
                pattern: {
                    value: /^\+?[0-9\s-()]{7,20}$/,
                    message: 'Некорректный формат телефона'
                }
            })}
        />


        {/* 3. EMAIL FIELD */}
        <input
            type="email"
            placeholder="Email"
            {...register('email', { 
                required: 'Введите email',
                pattern: {
                    value: /^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i, 
                    message: 'Некорректный формат email'
                }
            })}
        />
        {/* ❌ УДАЛЕНО: {errors.email && <p className="error">{errors.email.message}</p>} */}

        {/* Кнопка */}
        <button type="submit">
          Get a discount
        </button>

    </form>
  );
};

export default CouponForm;
